     1→import { useState, useCallback, useEffect } from 'react';
     2→import {
     3→  Button,
     4→  Card,
     5→  CardBody,
     6→  CardTitle,
     7→  Content,
     8→  EmptyState,
     9→  EmptyStateBody,
    10→  EmptyStateFooter,
    11→  EmptyStateActions,
    12→  Label,
    13→  Masthead,
    14→  MastheadBrand,
    15→  MastheadMain,
    16→  Page,
    17→  PageSection,
    18→  Spinner,
    19→  Title,
    20→} from '@patternfly/react-core';
    21→import { FolderOpenIcon, CogIcon, FolderIcon } from '@patternfly/react-icons';
    22→import { TabBar, KanbanBoard, LogPanel, TerminalPanel, ProjectSelector, ProgressCard, Settings, TaskModal } from './components';
    23→import type { HQSettings, TaskData } from './components';
    24→import type { LogEntry } from './components';
    25→import type { Project, Feature } from './state/store';
    26→import { listen } from '@tauri-apps/api/event';
    27→import { invoke } from '@tauri-apps/api/core';
    28→
    29→// PTY output event payload
    30→interface PtyOutputEvent {
    31→  process_id: string;
    32→  data: string;
    33→}
    34→
    35→// Process info for log panel
    36→interface ProcessInfo {
    37→  id: string;
    38→  name: string;
    39→}
    40→
    41→// Initialize harness database if it doesn't exist
    42→async function initializeHarnessIfNeeded(projectPath: string): Promise<boolean> {
    43→  try {
    44→    // Try to run status command - if it fails, db doesn't exist
    45→    await invoke<string>('run_harness_command', {
    46→      projectPath,
    47→      args: ['db', 'status'],
    48→    });
    49→    return true; // Already initialized
    50→  } catch {
    51→    // Database doesn't exist, initialize it
    52→    try {
    53→      await invoke<string>('run_harness_command', {
    54→        projectPath,
    55→        args: ['init'],
    56→      });
    57→      console.log('Harness database initialized for:', projectPath);
    58→      return true;
    59→    } catch (initError) {
    60→      console.error('Failed to initialize harness:', initError);
    61→      return false;
    62→    }
    63→  }
    64→}
    65→
    66→// Fetch tasks from harness CLI and convert to Feature format
    67→async function fetchProjectFeatures(projectPath: string): Promise<Feature[]> {
    68→  try {
    69→    const result = await invoke<string>('run_harness_command', {
    70→      projectPath,
    71→      args: ['task', 'list', '--format', 'json'],
    72→    });
    73→
    74→    const response = JSON.parse(result);
    75→    // CLI returns paginated response: { items: [...], has_next, has_prev, ... }
    76→    const tasks = response.items || response;
    77→    if (!Array.isArray(tasks)) return [];
    78→
    79→    return tasks.map((task: {
    80→      id: string;
    81→      title: string;
    82→      description?: string;
    83→      status: string;
    84→      category?: string;
    85→      is_passed?: boolean;
    86→    }) => ({
    87→      id: task.id,
    88→      description: task.title,
    89→      category: task.category || 'general',
    90→      priority: 'medium',
    91→      status: task.status.toLowerCase(),
    92→      passes: task.is_passed || task.status.toLowerCase() === 'done',
    93→      steps: task.description ? [task.description] : [],
    94→    }));
    95→  } catch (error) {
    96→    console.error('Failed to fetch project features:', error);
    97→    return [];
    98→  }
    99→}
   100→
   101→function App() {
   102→  // Project state - start empty, no mock projects
   103→  const [projects, setProjects] = useState<Project[]>([]);
   104→  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
   105→
   106→  // Features state - fetched from harness CLI
   107→  const [features, setFeatures] = useState<Feature[]>([]);
   108→  const [isLoadingFeatures, setIsLoadingFeatures] = useState(false);
   109→
   110→  // Project selector dialog state
   111→  const [isProjectSelectorOpen, setIsProjectSelectorOpen] = useState(false);
   112→
   113→  // Settings dialog state
   114→  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
   115→  const [settings, setSettings] = useState<HQSettings>({
   116→    theme: 'system',
   117→    logBufferSize: 10000,
   118→    defaultShell: '/bin/zsh',
   119→    ptyRows: 24,
   120→    ptyCols: 80,
   121→    autoScrollLogs: true,
   122→    showTimestamps: true,
   123→  });
   124→
   125→  // Log state - starts empty, filled by PTY events
   126→  const [logs, setLogs] = useState<LogEntry[]>([]);
   127→  const [processes, setProcesses] = useState<ProcessInfo[]>([]);
   128→
   129→  // Task modal state
   130→  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
   131→  const [editingTask, setEditingTask] = useState<Feature | undefined>(undefined);
   132→
   133→  // Open project selector on first launch if no projects
   134→  useEffect(() => {
   135→    if (projects.length === 0) {
   136→      setIsProjectSelectorOpen(true);
   137→    }
   138→  }, []);
   139→
   140→  // Fetch features when active project changes (initialize harness if needed)
   141→  useEffect(() => {
   142→    const activeProject = projects.find(p => p.id === activeProjectId);
   143→    if (activeProject) {
   144→      setIsLoadingFeatures(true);
   145→      // First ensure harness is initialized, then fetch features
   146→      initializeHarnessIfNeeded(activeProject.path)
   147→        .then((initialized) => {
   148→          if (initialized) {
   149→            return fetchProjectFeatures(activeProject.path);
   150→          }
   151→          return [];
   152→        })
   153→        .then(setFeatures)
   154→        .finally(() => setIsLoadingFeatures(false));
   155→    } else {
   156→      setFeatures([]);
   157→    }
   158→  }, [activeProjectId, projects]);
   159→
   160→  // Listen for menu events
   161→  useEffect(() => {
   162→    const listeners = [
   163→      listen('menu:open_project', () => {
   164→        setIsProjectSelectorOpen(true);
   165→      }),
   166→      listen('menu:new_tab', () => {
   167→        handleAddProject();
   168→      }),
   169→      listen('menu:close_tab', () => {
   170→        if (activeProjectId) {
   171→          handleCloseProject(activeProjectId);
   172→        }
   173→      }),
   174→      listen('menu:settings', () => {
   175→        setIsSettingsOpen(true);
   176→      }),
   177→    ];
   178→
   179→    return () => {
   180→      listeners.forEach(async (unlistenPromise) => {
   181→        const unlisten = await unlistenPromise;
   182→        unlisten();
   183→      });
   184→    };
   185→  }, [activeProjectId]);
   186→
   187→  // Listen for PTY output events to populate logs
   188→  useEffect(() => {
   189→    const unlistenPromise = listen<PtyOutputEvent>('pty-output', (event) => {
   190→      const { process_id, data } = event.payload;
   191→
   192→      // Add process if not already tracked
   193→      setProcesses(prev => {
   194→        if (!prev.find(p => p.id === process_id)) {
   195→          return [...prev, { id: process_id, name: `Process ${process_id.slice(0, 8)}` }];
   196→        }
   197→        return prev;
   198→      });
   199→
   200→      // Add log entry
   201→      setLogs(prev => {
   202→        const newLogs = [...prev, {
   203→          timestamp: Date.now(),
   204→          processId: process_id,
   205→          processName: `Process ${process_id.slice(0, 8)}`,
   206→          message: data,
   207→          level: 'info' as const,
   208→        }];
   209→        // Keep only last N logs based on settings
   210→        return newLogs.slice(-settings.logBufferSize);
   211→      });
   212→    });
   213→
   214→    return () => {
   215→      unlistenPromise.then(fn => fn());
   216→    };
   217→  }, [settings.logBufferSize]);
   218→
   219→  const handleClearLogs = useCallback(() => {
   220→    setLogs([]);
   221→  }, []);
   222→
   223→  // Tab handlers
   224→  const handleSelectProject = useCallback((projectId: string) => {
   225→    setActiveProjectId(projectId);
   226→  }, []);
   227→
   228→  const handleCloseProject = useCallback((projectId: string) => {
   229→    setProjects((prev) => {
   230→      const filtered = prev.filter((p) => p.id !== projectId);
   231→      // If closing active tab, switch to previous or next
   232→      if (activeProjectId === projectId && filtered.length > 0) {
   233→        const idx = prev.findIndex((p) => p.id === projectId);
   234→        const newActive = filtered[Math.max(0, idx - 1)];
   235→        setActiveProjectId(newActive.id);
   236→      } else if (filtered.length === 0) {
   237→        setActiveProjectId(null);
   238→      }
   239→      return filtered;
   240→    });
   241→  }, [activeProjectId]);
   242→
   243→  const handleAddProject = useCallback(() => {
   244→    setIsProjectSelectorOpen(true);
   245→  }, []);
   246→
   247→  // Handle selecting a project from the project selector
   248→  const handleSelectProjectFromDialog = useCallback((path: string, name: string) => {
   249→    // Check if project is already open
   250→    const existing = projects.find(p => p.path === path);
   251→    if (existing) {
   252→      setActiveProjectId(existing.id);
   253→      return;
   254→    }
   255→
   256→    const id = `proj-${Date.now()}`;
   257→    const newProject: Project = {
   258→      id,
   259→      path,
   260→      name,
   261→      harness: {
   262→        progressFile: '.harness/progress.txt',
   263→        featuresFile: '.harness/features.json',
   264→      },
   265→    };
   266→    setProjects((prev) => [...prev, newProject]);
   267→    setActiveProjectId(id);
   268→  }, [projects]);
   269→
   270→  const handleReorderProjects = useCallback((order: string[]) => {
   271→    setProjects((prev) => {
   272→      const projectMap = new Map(prev.map((p) => [p.id, p]));
   273→      return order.map((id) => projectMap.get(id)).filter(Boolean) as Project[];
   274→    });
   275→  }, []);
   276→
   277→  // Refresh features for active project
   278→  const handleRefreshFeatures = useCallback(() => {
   279→    const activeProject = projects.find(p => p.id === activeProjectId);
   280→    if (activeProject) {
   281→      setIsLoadingFeatures(true);
   282→      fetchProjectFeatures(activeProject.path)
   283→        .then(setFeatures)
   284→        .finally(() => setIsLoadingFeatures(false));
   285→    }
   286→  }, [activeProjectId, projects]);
   287→
   288→  // Task CRUD handlers
   289→  const handleOpenAddTask = useCallback(() => {
   290→    setEditingTask(undefined);
   291→    setIsTaskModalOpen(true);
   292→  }, []);
   293→
   294→  const handleOpenEditTask = useCallback((task: Feature) => {
   295→    setEditingTask(task);
   296→    setIsTaskModalOpen(true);
   297→  }, []);
   298→
   299→  const handleCloseTaskModal = useCallback(() => {
   300→    setIsTaskModalOpen(false);
   301→    setEditingTask(undefined);
   302→  }, []);
   303→
   304→  const handleSaveTask = useCallback(async (taskData: TaskData, taskId?: string) => {
   305→    const activeProject = projects.find(p => p.id === activeProjectId);
   306→    if (!activeProject) {
   307→      throw new Error('No active project selected');
   308→    }
   309→
   310→    const args = taskId
   311→      ? ['task', 'update', taskId]
   312→      : ['task', 'add', taskData.title];
   313→
   314→    // Add flags for update or creation
   315→    if (taskId) {
   316→      args.push('--title', taskData.title);
   317→    }
   318→    if (taskData.description) {
   319→      args.push('--description', taskData.description);
   320→    }
   321→    args.push('--status', taskData.status.toLowerCase());
   322→    if (taskData.category) {
   323→      args.push('--category', taskData.category);
   324→    }
   325→
   326→    try {
   327→      await invoke('run_harness_command', {
   328→        projectPath: activeProject.path,
   329→        args,
   330→      });
   331→      // Refresh the task list
   332→      handleRefreshFeatures();
   333→    } catch (error) {
   334→      const message = error instanceof Error ? error.message : String(error);
   335→      // Extract the actual error from "Harness command failed: Error: ..."
   336→      const match = message.match(/Error:\s*(.+)/);
   337→      throw new Error(match ? match[1] : message);
   338→    }
   339→  }, [activeProjectId, projects, handleRefreshFeatures]);
   340→
   341→  const handleDeleteTask = useCallback(async (taskId: string) => {
   342→    const activeProject = projects.find(p => p.id === activeProjectId);
   343→    if (!activeProject) return;
   344→
   345→    // Confirm before deleting
   346→    if (!window.confirm('Are you sure you want to delete this task?')) {
   347→      return;
   348→    }
   349→
   350→    await invoke('run_harness_command', {
   351→      projectPath: activeProject.path,
   352→      args: ['task', 'delete', taskId],
   353→    });
   354→
   355→    // Refresh the task list
   356→    handleRefreshFeatures();
   357→  }, [activeProjectId, projects, handleRefreshFeatures]);
   358→
   359→  const handleMoveTask = useCallback(async (taskId: string, newStatus: string) => {
   360→    const activeProject = projects.find(p => p.id === activeProjectId);
   361→    if (!activeProject) return;
   362→
   363→    try {
   364→      await invoke('run_harness_command', {
   365→        projectPath: activeProject.path,
   366→        args: ['task', 'update', taskId, '--status', newStatus.toLowerCase()],
   367→      });
   368→      // Refresh the task list
   369→      handleRefreshFeatures();
   370→    } catch (error) {
   371→      console.error('Failed to move task:', error);
   372→    }
   373→  }, [activeProjectId, projects, handleRefreshFeatures]);
   374→
   375→  // Get active project
   376→  const activeProject = projects.find((p) => p.id === activeProjectId);
   377→
   378→  // Calculate stats from actual features
   379→  const stats = {
   380→    completed: features.filter(f => f.status === 'done').length,
   381→    total: features.length,
   382→  };
   383→
   384→  const masthead = (
   385→    <Masthead>
   386→      <MastheadMain>
   387→        <MastheadBrand>
   388→          <Title headingLevel="h1" size="xl">HQ</Title>
   389→        </MastheadBrand>
   390→        <Label color="blue" isCompact>Harness Orchestrator</Label>
   391→      </MastheadMain>
   392→    </Masthead>
   393→  );
   394→
   395→  return (
   396→    <Page masthead={masthead}>
   397→      {/* Tab Bar */}
   398→      <TabBar
   399→        projects={projects}
   400→        activeProjectId={activeProjectId || ''}
   401→        onSelect={handleSelectProject}
   402→        onClose={handleCloseProject}
   403→        onAdd={handleAddProject}
   404→        onReorder={handleReorderProjects}
   405→      />
   406→
   407→      {/* Empty State when no projects */}
   408→      {projects.length === 0 && (
   409→        <PageSection>
   410→          <EmptyState
   411→            titleText="No Projects Open"
   412→            headingLevel="h2"
   413→            icon={FolderIcon}
   414→          >
   415→            <EmptyStateBody>
   416→              Open a Harness project to start managing your AI agent development sessions.
   417→              Projects with a <code>.harness</code> directory can be opened and tracked.
   418→            </EmptyStateBody>
   419→            <EmptyStateFooter>
   420→              <EmptyStateActions>
   421→                <Button
   422→                  variant="primary"
   423→                  icon={<FolderOpenIcon />}
   424→                  onClick={handleAddProject}
   425→                >
   426→                  Open Project
   427→                </Button>
   428→              </EmptyStateActions>
   429→            </EmptyStateFooter>
   430→          </EmptyState>
   431→        </PageSection>
   432→      )}
   433→
   434→      {/* Project Content - only show when there's an active project */}
   435→      {activeProject && (
   436→        <>
   437→          <PageSection>
   438→            <Card>
   439→              <CardTitle>{activeProject.name}</CardTitle>
   440→              <CardBody>
   441→                <Content component="p">
   442→                  <strong>Path:</strong> {activeProject.path}
   443→                </Content>
   444→                <Content component="p">
   445→                  <strong>Tasks:</strong> {stats.completed}/{stats.total} complete
   446→                </Content>
   447→                <div style={{ marginTop: '16px', display: 'flex', gap: '8px' }}>
   448→                  <Button
   449→                    variant="secondary"
   450→                    icon={<CogIcon />}
   451→                    onClick={() => setIsSettingsOpen(true)}
   452→                  >
   453→                    Settings
   454→                  </Button>
   455→                  <Button
   456→                    variant="secondary"
   457→                    icon={<FolderOpenIcon />}
   458→                    onClick={handleAddProject}
   459→                  >
   460→                    Open Another Project
   461→                  </Button>
   462→                </div>
   463→              </CardBody>
   464→            </Card>
   465→          </PageSection>
   466→
   467→          {/* Progress Card */}
   468→          <PageSection>
   469→            <ProgressCard projectPath={activeProject.path} onRefresh={handleRefreshFeatures} />
   470→          </PageSection>
   471→
   472→          {/* Kanban Board */}
   473→          <PageSection>
   474→            <Card>
   475→              <CardTitle>
   476→                Task Board
   477→                {isLoadingFeatures && <Spinner size="md" style={{ marginLeft: 8 }} />}
   478→              </CardTitle>
   479→              <CardBody>
   480→                <KanbanBoard
   481→                  features={features}
   482→                  onAddTask={handleOpenAddTask}
   483→                  onEditTask={handleOpenEditTask}
   484→                  onDeleteTask={handleDeleteTask}
   485→                  onMoveTask={handleMoveTask}
   486→                />
   487→              </CardBody>
   488→            </Card>
   489→          </PageSection>
   490→
   491→          {/* Log Panel */}
   492→          <PageSection>
   493→            <Card>
   494→              <CardTitle>Process Logs</CardTitle>
   495→              <CardBody>
   496→                {logs.length > 0 ? (
   497→                  <LogPanel
   498→                    logs={logs}
   499→                    processes={processes}
   500→                    onClear={handleClearLogs}
   501→                    height={300}
   502→                  />
   503→                ) : (
   504→                  <EmptyState titleText="No Logs" headingLevel="h4">
   505→                    <EmptyStateBody>
   506→                      Process logs will appear here when you start a terminal session.
   507→                    </EmptyStateBody>
   508→                  </EmptyState>
   509→                )}
   510→              </CardBody>
   511→            </Card>
   512→          </PageSection>
   513→
   514→          {/* Terminal Panel */}
   515→          <PageSection>
   516→            <TerminalPanel height={250} />
   517→          </PageSection>
   518→        </>
   519→      )}
   520→
   521→      {/* Project Selector Dialog */}
   522→      <ProjectSelector
   523→        isOpen={isProjectSelectorOpen}
   524→        onClose={() => setIsProjectSelectorOpen(false)}
   525→        onSelectProject={handleSelectProjectFromDialog}
   526→      />
   527→
   528→      {/* Settings Dialog */}
   529→      <Settings
   530→        isOpen={isSettingsOpen}
   531→        onClose={() => setIsSettingsOpen(false)}
   532→        onSettingsChange={setSettings}
   533→      />
   534→
   535→      {/* Task Modal */}
   536→      <TaskModal
   537→        isOpen={isTaskModalOpen}
   538→        onClose={handleCloseTaskModal}
   539→        onSave={handleSaveTask}
   540→        task={editingTask}
   541→      />
   542→    </Page>
   543→  );
   544→}
   545→
   546→export default App;
   547→

