import { useEffect, useState, useCallback, useRef } from "react";
import {
  Button,
  Card,
  CardBody,
  CardTitle,
  TextInput,
  Label,
  Flex,
  FlexItem,
  Alert,
  TextInputGroup,
  TextInputGroupMain,
  TextInputGroupUtilities,
} from "@patternfly/react-core";
import { PlayIcon, StopIcon, TerminalIcon, KeyIcon } from "@patternfly/react-icons";
import {
  isTauri,
  isDevBridgeAvailable,
  setDevBridgeToken,
  ptySpawn,
  ptyWrite,
  ptyKill,
  onPtyOutput,
  onPtyExit,
  ProcessInfo,
} from "../lib/rpc";

type UnlistenFn = () => void;

interface TerminalPanelProps {
  height?: number;
  defaultCwd?: string;
}

type BackendMode = "tauri" | "dev-bridge" | "none";

export function TerminalPanel({
  height = 300,
  defaultCwd,
}: TerminalPanelProps) {
  const [processInfo, setProcessInfo] = useState<ProcessInfo | null>(null);
  const [output, setOutput] = useState<string[]>([]);
  const [input, setInput] = useState("");
  const [status, setStatus] = useState<"idle" | "running" | "stopped">("idle");
  const [backendMode, setBackendMode] = useState<BackendMode>("none");
  const [tokenInput, setTokenInput] = useState("");
  const [showTokenInput, setShowTokenInput] = useState(false);
  const outputRef = useRef<HTMLDivElement>(null);
  const unlistenRef = useRef<UnlistenFn[]>([]);

  // Check backend availability on mount
  useEffect(() => {
    const checkBackend = async () => {
      if (isTauri()) {
        setBackendMode("tauri");
        return;
      }

      const devBridgeAvailable = await isDevBridgeAvailable();
      if (devBridgeAvailable) {
        setBackendMode("dev-bridge");
      } else {
        setBackendMode("none");
      }
    };

    checkBackend();
  }, []);

  // Auto-scroll to bottom when output changes
  useEffect(() => {
    if (outputRef.current) {
      outputRef.current.scrollTop = outputRef.current.scrollHeight;
    }
  }, [output]);

  // Setup event listeners when process starts
  useEffect(() => {
    if (!processInfo || backendMode === "none") return;

    const setupListeners = async () => {
      const unlistenOutput = await onPtyOutput((payload) => {
        if (payload.id === processInfo.id) {
          setOutput((prev) => [...prev, payload.data]);
        }
      });

      const unlistenExit = await onPtyExit((payload) => {
        if (payload.id === processInfo.id) {
          setStatus("stopped");
          setOutput((prev) => [
            ...prev,
            `\n\x1b[33m[Process exited with code: ${payload.code ?? "unknown"}]\x1b[0m\n`,
          ]);
        }
      });

      unlistenRef.current = [unlistenOutput, unlistenExit];
    };

    setupListeners();

    return () => {
      unlistenRef.current.forEach((unlisten) => unlisten());
      unlistenRef.current = [];
    };
  }, [processInfo, backendMode]);

  // Handle token submission
  const handleTokenSubmit = useCallback(() => {
    if (tokenInput.trim()) {
      setDevBridgeToken(tokenInput.trim());
      setShowTokenInput(false);
      setTokenInput("");

      // Re-check backend availability
      isDevBridgeAvailable().then((available) => {
        if (available) {
          setBackendMode("dev-bridge");
          setOutput((prev) => [
            ...prev,
            "\x1b[32m[Token set. Dev bridge connected.]\x1b[0m\n",
          ]);
        }
      });
    }
  }, [tokenInput]);

  // Spawn a new shell process
  const handleSpawn = useCallback(async () => {
    if (backendMode === "none") {
      setOutput([
        "PTY requires either the native Tauri app or the dev bridge. This feature is not available in the browser without the dev bridge.",
      ]);
      return;
    }

    try {
      // Detect shell based on platform
      const shell = navigator.userAgent.includes("Mac")
        ? "/bin/zsh"
        : "/bin/bash";
      const cwd = defaultCwd || "/";

      const info = await ptySpawn(shell, [], cwd, 24, 80);

      setProcessInfo(info);
      setOutput([
        `\x1b[32m[Shell started: ${info.cmd}]\x1b[0m\n`,
        `\x1b[36m[Mode: ${backendMode === "tauri" ? "Native Tauri" : "Dev Bridge RPC"}]\x1b[0m\n`,
      ]);
      setStatus("running");
    } catch (error) {
      setOutput((prev) => [...prev, `\x1b[31m[Error: ${error}]\x1b[0m\n`]);
    }
  }, [defaultCwd, backendMode]);

  // Kill the current process
  const handleKill = useCallback(async () => {
    if (!processInfo || backendMode === "none") return;

    try {
      await ptyKill(processInfo.id);
      setStatus("stopped");
    } catch (error) {
      setOutput((prev) => [...prev, `\x1b[31m[Kill error: ${error}]\x1b[0m\n`]);
    }
  }, [processInfo, backendMode]);

  // Send command to the process
  const handleSend = useCallback(async () => {
    if (!processInfo || !input.trim() || backendMode === "none") return;

    try {
      await ptyWrite(processInfo.id, input + "\n");
      setInput("");
    } catch (error) {
      setOutput((prev) => [
        ...prev,
        `\x1b[31m[Write error: ${error}]\x1b[0m\n`,
      ]);
    }
  }, [processInfo, input, backendMode]);

  // Handle Enter key in input
  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent) => {
      if (event.key === "Enter") {
        handleSend();
      }
    },
    [handleSend]
  );

  // Handle token input Enter key
  const handleTokenKeyDown = useCallback(
    (event: React.KeyboardEvent) => {
      if (event.key === "Enter") {
        handleTokenSubmit();
      }
    },
    [handleTokenSubmit]
  );

  // Parse ANSI codes for display
  const parseAnsi = (text: string): string => {
    return text;
  };

  const isBackendAvailable = backendMode !== "none";

  return (
    <Card>
      <CardTitle>
        <Flex>
          <FlexItem>
            <TerminalIcon /> Terminal (PTY)
          </FlexItem>
          <FlexItem>
            <Label
              color={
                backendMode === "tauri"
                  ? "blue"
                  : backendMode === "dev-bridge"
                    ? "teal"
                    : "grey"
              }
            >
              {backendMode === "tauri"
                ? "Native"
                : backendMode === "dev-bridge"
                  ? "Dev Bridge"
                  : "No Backend"}
            </Label>
          </FlexItem>
          <FlexItem>
            <Label
              color={
                status === "running"
                  ? "green"
                  : status === "stopped"
                    ? "red"
                    : "grey"
              }
            >
              {status}
            </Label>
          </FlexItem>
        </Flex>
      </CardTitle>
      <CardBody>
        {/* Warning when no backend available */}
        {backendMode === "none" && !showTokenInput && (
          <Alert
            variant="warning"
            title="No Backend Available"
            isInline
            style={{ marginBottom: "8px" }}
            actionLinks={
              <Button
                variant="link"
                onClick={() => setShowTokenInput(true)}
                style={{ paddingLeft: 0 }}
              >
                <KeyIcon /> Set Dev Bridge Token
              </Button>
            }
          >
            PTY requires the native Tauri app or dev bridge connection. Start
            the app with <code>bun tauri dev</code> and copy the token from the
            terminal.
          </Alert>
        )}

        {/* Token input */}
        {showTokenInput && (
          <div style={{ marginBottom: "8px" }}>
            <TextInputGroup>
              <TextInputGroupMain
                value={tokenInput}
                onChange={(_e, val) => setTokenInput(val)}
                onKeyDown={handleTokenKeyDown}
                placeholder="Paste dev bridge token from terminal..."
                aria-label="Dev bridge token"
              />
              <TextInputGroupUtilities>
                <Button variant="control" onClick={handleTokenSubmit}>
                  Set
                </Button>
                <Button
                  variant="plain"
                  onClick={() => setShowTokenInput(false)}
                >
                  Cancel
                </Button>
              </TextInputGroupUtilities>
            </TextInputGroup>
          </div>
        )}

        {/* Dev bridge mode info */}
        {backendMode === "dev-bridge" && (
          <Alert
            variant="info"
            title="Dev Bridge Mode"
            isInline
            style={{ marginBottom: "8px" }}
          >
            Connected via RPC bridge. PTY output is streamed over WebSocket.
          </Alert>
        )}

        {/* Output area */}
        <div
          ref={outputRef}
          style={{
            height: `${height}px`,
            backgroundColor: "#1e1e1e",
            color: "#d4d4d4",
            fontFamily: "monospace",
            fontSize: "13px",
            padding: "8px",
            overflowY: "auto",
            whiteSpace: "pre-wrap",
            borderRadius: "4px",
            marginBottom: "8px",
          }}
        >
          {output.map((line, i) => (
            <span key={i}>{parseAnsi(line)}</span>
          ))}
          {output.length === 0 && (
            <span style={{ color: "#888" }}>
              {isBackendAvailable
                ? 'Click "Start Shell" to spawn a PTY process...'
                : "No backend available. Start bun tauri dev and set the token."}
            </span>
          )}
        </div>

        {/* Controls */}
        <Flex>
          {status !== "running" ? (
            <FlexItem>
              <Button
                variant="primary"
                onClick={handleSpawn}
                icon={<PlayIcon />}
                isDisabled={!isBackendAvailable}
              >
                Start Shell
              </Button>
            </FlexItem>
          ) : (
            <>
              <FlexItem grow={{ default: "grow" }}>
                <TextInput
                  value={input}
                  onChange={(_e, val) => setInput(val)}
                  onKeyDown={handleKeyDown}
                  placeholder="Type command and press Enter..."
                  aria-label="Command input"
                />
              </FlexItem>
              <FlexItem>
                <Button variant="secondary" onClick={handleSend}>
                  Send
                </Button>
              </FlexItem>
              <FlexItem>
                <Button
                  variant="danger"
                  onClick={handleKill}
                  icon={<StopIcon />}
                >
                  Kill
                </Button>
              </FlexItem>
            </>
          )}
        </Flex>

        {/* Process info */}
        {processInfo && (
          <div style={{ marginTop: "8px", fontSize: "12px", color: "#888" }}>
            <strong>Process ID:</strong> {processInfo.id} |{" "}
            <strong>Size:</strong> {processInfo.cols}x{processInfo.rows} |{" "}
            <strong>CWD:</strong> {processInfo.cwd}
          </div>
        )}
      </CardBody>
    </Card>
  );
}

//! Dev Bridge - Secure RPC bridge for browser-to-native communication
//!
//! This module provides a development-only WebSocket server that mirrors Tauri commands,
//! allowing Playwright and other browser-based tools to interact with native features.
//!
//! SECURITY:
//! - Only compiled in debug mode (#[cfg(debug_assertions)])
//! - localhost-only binding (127.0.0.1)
//! - Token-based authentication
//! - Command allowlist (no arbitrary execution)

#![cfg(debug_assertions)]

use crate::pty::{PtyManager, ProcessInfo};
use axum::{
    extract::{
        ws::{Message, WebSocket, WebSocketUpgrade},
        Query, State,
    },
    http::StatusCode,
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use futures_util::{SinkExt, StreamExt};
use parking_lot::Mutex;
use serde::{Deserialize, Serialize};
use std::sync::Arc;
use tokio::sync::broadcast;
use tower_http::cors::{Any, CorsLayer};

/// Default port for dev bridge server
const DEFAULT_PORT: u16 = 9876;

/// RPC Request format
#[derive(Debug, Deserialize)]
pub struct RpcRequest {
    /// Unique request ID for response correlation
    pub id: String,
    /// Command name (e.g., "pty_spawn", "pty_write")
    pub cmd: String,
    /// Command arguments as JSON
    #[serde(default)]
    pub args: serde_json::Value,
}

/// RPC Response format
#[derive(Debug, Serialize)]
pub struct RpcResponse {
    /// Request ID for correlation
    pub id: String,
    /// Success flag
    pub success: bool,
    /// Result data (if success)
    #[serde(skip_serializing_if = "Option::is_none")]
    pub result: Option<serde_json::Value>,
    /// Error message (if failure)
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error: Option<String>,
}

/// Event broadcast to clients
#[derive(Debug, Clone, Serialize)]
pub struct RpcEvent {
    /// Event type (e.g., "pty-output", "pty-exit")
    pub event: String,
    /// Event payload
    pub payload: serde_json::Value,
}

/// Query params for auth
#[derive(Debug, Deserialize)]
pub struct AuthQuery {
    pub token: Option<String>,
}

/// Dev Bridge server state
pub struct DevBridgeState {
    /// Auth token (generated at startup)
    pub token: String,

// Prevents additional console window on Windows in release, DO NOT REMOVE!!
#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]

fn main() {
    hq_lib::run()
}

